   373→func validateNamespaceWithOptionalName(namespace string, name ...string) error {
   374→	if msgs := rest.IsValidPathSegmentName(namespace); len(msgs) != 0 {
   375→		return fmt.Errorf("invalid namespace %q: %v", namespace, msgs)
   376→	}
   377→	if len(name) > 1 {
   378→		panic("Invalid number of names")
   379→	} else if len(name) == 1 {
   380→		if msgs := rest.IsValidPathSegmentName(name[0]); len(msgs) != 0 {
   381→			return fmt.Errorf("invalid resource name %q: %v", name[0], msgs)
   382→		}
   383→	}
   384→	return nil
   385→}
